            5 => self.list(pass),
            6 => self.list(pass),
            7 => self.list(pass),
            8 => self.list(pass),
            9 => self.list(pass),
            10 => self.list(pass),
            11 => self.list(pass),
            12 => self.list(pass),
            13 => self.list(pass),
            14 => self.list(pass),
            15 => self.list(pass),
            16 => self.list(pass),
            17 => self.list(pass),
            18 => self.sexp(.@"int", &.{pass[0]}),
            19 => self.sexp(.@"real", &.{pass[0]}),
            20 => self.sexp(.@"string", &.{pass[0]}),
            21 => self.sexp(.@"char", &.{pass[0]}),
