    fn tokenToSymbol(_: *BaseParser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"integer" => 19,
            .@"real" => 20,
            .@"string" => 21,
            .@"char" => 22,
            .@"keyword" => 23,
            .@"ident" => 24,
            .@"hash_lbrace" => 31,
            .@"unquote_splicing_tok" => 35,
            .@"hash_lparen" => 37,
            .@"hash_discard" => 38,
            .@"lparen" => 25,
            .@"rparen" => 26,
            .@"lbracket" => 27,
            .@"rbracket" => 28,
            .@"lbrace" => 29,
            .@"rbrace" => 30,
            .@"quote_tok" => 32,
            .@"syntax_quote_tok" => 33,
            .@"unquote_tok" => 34,
            .@"deref_tok" => 36,
            .@"caret" => 39,
            else => 2, // error
